class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        queue = deque(range(1, 10))
        res = []
        while queue:
            num = queue.popleft()
            if low <= num <= high:
                res.append(num)
            last = num % 10
            if last < 9:
                next_num = num * 10 + (last + 1)
                if next_num <= high:
                    queue.append(next_num)
        return res

